(function(){'use strict';const M_ID='jf-insights-modal',B_ID='jf-insights-nav-btn';let f=false;const eS=()=>{if(document.getElementById('jf-insights-style'))return;const s=document.createElement('style');s.id='jf-insights-style';s.textContent=`#${M_ID}{position:fixed;top:0;left:0;width:100vw;height:100vh;background:rgba(0,0,0,.7);backdrop-filter:blur(35px) saturate(1.5);-webkit-backdrop-filter:blur(35px) saturate(1.5);z-index:100000;display:none;justify-content:center;overflow-y:auto;color:#fff;font-family:'Noto Sans',sans-serif}#${M_ID}.active{display:flex}.insights-container{max-width:1000px;width:90%;margin:60px 0;animation:jf-insight-slide .5s cubic-bezier(.16,1,.3,1)}@keyframes jf-insight-slide{from{opacity:0;transform:translateY(30px) scale(.98)}to{opacity:1;transform:translateY(0) scale(1)}}.insights-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:40px}.insights-header h2{font-size:2rem;font-weight:700;margin:0;letter-spacing:-.5px}.insights-hero{background:linear-gradient(135deg,rgba(255,255,255,.08) 0,rgba(255,255,255,.03) 100%);border:1px solid rgba(255,255,255,.1);border-radius:24px;padding:40px;margin-bottom:24px;display:flex;flex-direction:column;align-items:center;text-align:center}.hero-val{font-size:4.5rem;font-weight:900;line-height:1;background:linear-gradient(to bottom,#fff,rgba(255,255,255,.7));-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin:10px 0}.insights-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:24px}.insight-card{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.08);padding:30px;border-radius:20px;display:flex;flex-direction:column}.insight-label{font-size:.8rem;text-transform:uppercase;letter-spacing:2px;color:rgba(255,255,255,.5);font-weight:700;margin-bottom:20px;display:flex;align-items:center;gap:8px}.insight-label i{font-size:1.2rem;color:var(--active-color,#10b981)}.stats-row{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:12px}.stats-row .val{font-size:1.8rem;font-weight:700}.stats-row .sub{font-size:.9rem;color:rgba(255,255,255,.5);margin-bottom:5px}.progress-bar{height:8px;background:rgba(255,255,255,.1);border-radius:10px;overflow:hidden;display:flex}.progress-fill{height:100%;transition:width 1.2s cubic-bezier(.16,1,.3,1)}.top-list{list-style:none;padding:0;margin:0}.top-list-item{display:flex;align-items:center;padding:14px 0;border-bottom:1px solid rgba(255,255,255,.05)}.top-list-item:last-child{border:none}.rank-number{width:28px;font-size:.8rem;font-weight:800;color:rgba(255,255,255,.3)}.item-name{flex:1;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-right:15px}.item-badge{font-size:.75rem;background:rgba(255,255,255,.1);padding:4px 10px;border-radius:12px;font-weight:700}.close-insights{background:#fff;border:none;color:#000;padding:12px 28px;border-radius:50px;cursor:pointer;font-weight:700;transition:transform .2s}.close-insights:hover{transform:scale(1.05)}.loading-state{height:100%;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:20px}.spinner{width:40px;height:40px;border:4px solid rgba(255,255,255,.1);border-top-color:var(--active-color,#10b981);border-radius:50%;animation:jf-spin 1s linear infinite}@keyframes jf-spin{to{transform:rotate(360deg)}}`;document.head.appendChild(s)},fT=t=>{const s=t/1e7;return{d:Math.floor(s/86400),h:Math.floor((s%86400)/3600)}},fD=async()=>{if(typeof ApiClient==='undefined')return;const u=ApiClient.getCurrentUserId(),r=await ApiClient.getJSON(ApiClient.getUrl(`Users/${u}/Items`,{Recursive:true,IncludeItemTypes:'Movie,Episode',Fields:'Genres,CumulativeRunTimeTicks,PlayCount',Filters:'IsPlayed'})),s={t:0,m:0,e:0,g:{},i:[]};if(r&&r.Items){r.Items.forEach(item=>{const p=item.UserData?item.UserData.PlayCount||0:0;if(p===0)return;if(item.Type==='Movie')s.m++;if(item.Type==='Episode')s.e++;s.t+=(item.RunTimeTicks||0)*p;if(item.Genres)item.Genres.forEach(g=>{s.g[g]=(s.g[g]||0)+1})});s.i=[...r.Items].sort((a,b)=>(b.UserData?.PlayCount||0)-(a.UserData?.PlayCount||0)).slice(0,5)}return s},rD=s=>{const t=fT(s.t),total=s.m+s.e,pct=total>0?(s.m/total)*100:0,sG=Object.entries(s.g).sort((a,b)=>b[1]-a[1]).slice(0,5),m=document.getElementById(M_ID);m.innerHTML=`<div class="insights-container"><div class="insights-header"><h2>Insights</h2><button class="close-insights" onclick="document.getElementById('${M_ID}').classList.remove('active')">Dismiss</button></div><div class="insights-hero"><div class="insight-label">Your Total Screen Time</div><div class="hero-val">${t.d}d ${t.h}h</div><div style="color:rgba(255,255,255,0.4); font-size:0.9rem; font-weight:500;">Calculated across ${total} unique items</div></div><div class="insights-grid"><div class="insight-card"><div class="insight-label"><i class="material-icons">pie_chart</i>Library Distribution</div><div class="stats-row"><span class="sub">Movies</span><span class="val">${s.m}</span></div><div class="stats-row"><span class="sub">Episodes</span><span class="val">${s.e}</span></div><div class="progress-bar"><div class="progress-fill" style="width:${pct}%; background:var(--active-color, #10b981);"></div><div class="progress-fill" style="width:${100-pct}%; background:#3b82f6;"></div></div></div><div class="insight-card"><div class="insight-label"><i class="material-icons">favorite</i>Top Preferences</div><ul class="top-list">${sG.length>0?sG.map(([n,c],i)=>`<li class="top-list-item"><span class="rank-number">0${i+1}</span><span class="item-name">${n}</span><span class="item-badge">${c}</span></li>`).join(''):'<li class="top-list-item" style="color:rgba(255,255,255,0.4)">Not enough data yet</li>'}</ul></div><div class="insight-card"><div class="insight-label"><i class="material-icons">history</i>Most Revisited</div><ul class="top-list">${s.i.length>0?s.i.map((item,i)=>`<li class="top-list-item"><span class="rank-number">0${i+1}</span><span class="item-name">${item.Name}</span><span class="item-badge" style="color:#facc15;">${item.UserData.PlayCount}x</span></li>`).join(''):'<li class="top-list-item" style="color:rgba(255,255,255,0.4)">Not enough data yet</li>'}</ul></div></div></div>`},oI=async()=>{if(f)return;const m=document.getElementById(M_ID)||cM();m.classList.add('active');m.innerHTML=`<div class="loading-state"><div class="spinner"></div><div style="font-weight:700; letter-spacing:1px; color:rgba(255,255,255,0.6); text-transform:uppercase; font-size:0.8rem;">Analyzing Watch History</div></div>`;f=true;try{const s=await fD();rD(s)}catch(e){m.innerHTML=`<div class="insights-container" style="text-align:center;"><h2>Could not sync data.</h2><button class="close-insights" onclick="location.reload()">Retry</button></div>`}finally{f=false}},cM=()=>{eS();const m=document.createElement('div');m.id=M_ID;document.body.appendChild(m);return m},iB=()=>{if(document.getElementById(B_ID))return;const h=document.querySelector('.headerRight');if(!h)return;const b=document.createElement('button');b.id=B_ID;b.className='paper-icon-button-light headerButton';b.title='Insights';b.innerHTML='<span class="material-icons">analytics</span>';b.addEventListener('click',oI);h.prepend(b)},init=()=>{iB();new MutationObserver(iB).observe(document.body,{childList:true,subtree:true})};if(document.readyState==='complete')init();else window.addEventListener('DOMContentLoaded',init)})();
